# Schema-constrained output + client-side validation + bounded retry.
from anthropic import Anthropic
from pydantic import BaseModel, ValidationError

client = Anthropic()

class Extraction(BaseModel):
    name: str
    amount: float
    currency: str

SCHEMA = {
    "type": "object",
    "properties": {
        "name": {"type": "string"},
        "amount": {"type": "number"},
        "currency": {"type": "string"},
    },
    "required": ["name", "amount", "currency"],
    "additionalProperties": False,
}

def extract(text: str, max_attempts: int = 3) -> Extraction:
    last_err = None
    for _ in range(max_attempts):
        resp = client.messages.create(
            model="claude-opus-4-8",
            max_tokens=512,
            system="Extract the payee, amount, and currency. Return only the JSON.",
            output_config={"format": {"type": "json_schema", "schema": SCHEMA}},
            messages=[{"role": "user", "content": text}],
        )
        # A refusal or max_tokens truncation can still yield unusable output.
        if resp.stop_reason == "refusal":
            raise RuntimeError("model refused the request")
        try:
            return Extraction.model_validate_json(resp.content[0].text)
        except (ValidationError, ValueError) as e:
            last_err = e  # retry: the schema was violated or output was truncated
    raise ValueError(f"failed to extract valid output: {last_err}")

