from typing import Callable, Any
from jsonschema import validate, ValidationError

# Each tool is registered with its handler, input schema, and a danger flag.
ToolSpec = dict[str, Any]

class ToolHandler:
    def __init__(self, confirm: Callable[[str, dict], bool]):
        # confirm(tool_name, args) -> True to allow a dangerous action.
        self._registry: dict[str, ToolSpec] = {}
        self._confirm = confirm

    def register(self, name: str, handler: Callable[[dict], str],
                 schema: dict, dangerous: bool = False) -> None:
        self._registry[name] = {
            "handler": handler,
            "schema": schema,
            "dangerous": dangerous,
        }

    def _result(self, tool_use_id: str, content: str,
                is_error: bool = False) -> dict:
        return {
            "type": "tool_result",
            "tool_use_id": tool_use_id,
            "content": content,
            "is_error": is_error,
        }

    def handle(self, name: str, args: dict, tool_use_id: str) -> dict:
        # 1. Allowlist: unknown tools never run.
        spec = self._registry.get(name)
        if spec is None:
            return self._result(
                tool_use_id, f"Tool '{name}' is not allowed.", is_error=True
            )

        # 2. Schema validation: reject adversarial / malformed arguments.
        try:
            validate(instance=args, schema=spec["schema"])
        except ValidationError as e:
            return self._result(
                tool_use_id, f"Invalid arguments: {e.message}", is_error=True
            )

        # 3. Human-in-the-loop gate for irreversible actions; deny by default.
        if spec["dangerous"] and not self._confirm(name, args):
            return self._result(
                tool_use_id, "Action denied: not confirmed by a human.",
                is_error=True,
            )

        # 4. Execute safely; never let a tool exception crash the loop.
        try:
            output = spec["handler"](args)
            return self._result(tool_use_id, output)
        except Exception as e:  # noqa: BLE001 - report, do not crash
            return self._result(
                tool_use_id, f"Tool execution failed: {e}", is_error=True
            )

